  }), mdx("h2", null, "\uC77C\uAD00\uC131 \uBCF4\uC7A5"), mdx("p", null, "\uBD84\uC0B0 \uC2DC\uC2A4\uD15C \uD658\uACBD\uC5D0\uC11C\uB294 \uC5EC\uD0DC \uC0B4\uD3B4\uBCF4\uC558\uB358 \uAC83\uCC98\uB7FC \uC5B4\uB5A4 \uC77C\uC774\uB4E0\uC9C0 \uBC8C\uC5B4\uC9C8 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC608\uB97C \uB4E4\uC5B4 \uBCF5\uC81C \uC9C0\uC5F0 \uBB38\uC81C\uAC00 \uBC1C\uC0DD\uD558\uBA74 \uB450 \uB178\uB4DC\uB294 \uC11C\uB85C \uB2E4\uB978 \uB370\uC774\uD130\uB97C \uAC00\uC9C0\uACE0 \uC788\uAC8C \uB429\uB2C8\uB2E4.\n\uBCF5\uC81C \uB370\uC774\uD130\uBCA0\uC774\uC2A4\uB294 \uB300\uBD80\uBD84 \uCD5C\uC18C\uD55C eventual consistency\uB97C \uBCF4\uC7A5\uD569\uB2C8\uB2E4. \uC2DC\uAC04\uC774 \uC9C0\uB098\uBA74 \uACB0\uAD6D \uAC19\uC740 \uB370\uC774\uD130\uB85C \uC218\uB834\uD558\uB294 \uAC83\uC744 \uAE30\uB300\uD55C\uB2E4\uB294 \uC758\uBBF8\uC785\uB2C8\uB2E4."), mdx("p", null, "\uBCF4\uD1B5\uC740 \uC131\uB2A5\uC744 \uC704\uD574 \uC774\uB7F0 \uC77C\uAD00\uC131\uC744 \uD3EC\uAE30\uD558\uAE34 \uD558\uC9C0\uB9CC, \uB54C\uB85C\uB294 \uAC15\uB825\uD55C \uC77C\uAD00\uC131\uC774 \uD544\uC694\uD560 \uB54C\uB3C4 \uC788\uC2B5\uB2C8\uB2E4. "), mdx("h3", null, "\uC120\uD615\uC131"), mdx("p", null, "\uC120\uD615\uC131\uC740 \uBC14\uB85C \uADF8 \uAC15\uB825\uD55C \uC77C\uAD00\uC131 \uC911 \uD558\uB098\uC785\uB2C8\uB2E4.\n\uAE30\uBCF8 \uC544\uC774\uB514\uC5B4\uB294 \uC2DC\uC2A4\uD15C\uC5D0 \uB370\uC774\uD130 \uBCF5\uC0AC\uBCF8\uC774 \uD558\uB098\uB9CC \uC788\uACE0 \uADF8 \uB370\uC774\uD130\uB97C \uB300\uC0C1\uC73C\uB85C \uC218\uD589\uD558\uB294 \uBAA8\uB4E0 \uC5F0\uC0B0\uC740 \uC6D0\uC790\uC801\uC778 \uAC83\uCC98\uB7FC \uBCF4\uC774\uAC8C \uB9CC\uB4DC\uB294 \uAC83\uC785\uB2C8\uB2E4.\nA \uAC00 \uC0C8\uB85C\uC6B4 \uAC12\uC744 \uC870\uD68C\uD588\uB2E4\uBA74 B \uC5ED\uC2DC \uC0C8\uB85C\uC6B4 \uAC12\uC744 \uC870\uD68C\uD560 \uC218 \uC788\uC5B4\uC57C \uD558\uC9C0, \uC608\uC804 \uAC12\uC744 \uBCF4\uC544\uC120 \uC548\uB41C\uB2E4\uB294 \uC758\uBBF8\uC785\uB2C8\uB2E4. \uC989 \uCD5C\uC2E0\uC131\uC744 \uBCF4\uC7A5(recency guarantee)\uD574\uC57C \uD55C\uB2E4\uB294 \uB73B\uC785\uB2C8\uB2E4."), mdx("p", null, "\uADF8\uB7FC \uC120\uD615\uC131\uC740 \uC5B8\uC81C \uD544\uC694\uD560\uAE4C\uC694?"), mdx("h4", null, "\uC7A0\uAE08\uACFC \uB9AC\uB354 \uC120\uCD9C"), mdx("p", null, "\uB9AC\uB354\uB97C \uC120\uCD9C\uD558\uB294 \uD55C \uAC00\uC9C0 \uBC29\uBC95\uC740 lock\uC744 \uC7A1\uB294 \uAC83\uC785\uB2C8\uB2E4. \uBAA8\uB4E0 \uB178\uB4DC\uAC00 \uC2DC\uC791\uD560 \uB54C lock\uC744 \uC7A1\uAE30 \uC2DC\uC791\uD558\uACE0 \uC131\uACF5\uD55C node\uAC00 \uB9AC\uB354\uAC00 \uB418\uB294 \uC2DD\uC785\uB2C8\uB2E4. \uC774\uB807\uAC8C \uD558\uB294 \uC774\uC720\uB294 \uB3D9\uC2DC\uC5D0 \uC5EC\uB7EC \uB9AC\uB354\uAC00 \uB098\uC624\uB294 \uC0C1\uD669\uC744 \uBC29\uC9C0\uD558\uAE30 \uC704\uD574\uC11C\uC785\uB2C8\uB2E4.\n\uC774 \uB54C lock\uC744 \uAD6C\uD604\uD55C \uBC29\uC2DD\uC774 \uC120\uD615\uC801\uC774\uC9C0 \uC54A\uB2E4\uBA74 \uB2E8\uC77C\uD55C \uB178\uB4DC\uB97C \uC120\uCD9C\uD558\uAE30 \uC5B4\uB824\uC6CC\uC9D1\uB2C8\uB2E4. "), mdx("h4", null, "\uC81C\uC57D \uC870\uAC74\uACFC \uC720\uC77C\uC131 \uBCF4\uC7A5"), mdx("p", null, "RDB\uC5D0\uC11C \uC804\uD615\uC801\uC73C\uB85C \uBCFC \uC218 \uC788\uB294 unique constraint \uB294 \uC120\uD615\uC131\uC774 \uD544\uC694\uD569\uB2C8\uB2E4.\n\uB450 \uC0AC\uB78C\uC774 \uAC19\uC740 \uC774\uB984\uC73C\uB85C \uACC4\uC815\uC744 \uC0DD\uC131\uD558\uB824\uACE0 \uD558\uBA74 \uB458 \uC911 \uD55C \uBA85\uC740 \uC624\uB958\uB97C \uBC1B\uC544\uC57C \uD569\uB2C8\uB2E4.\n\uC740\uD589 \uACC4\uC88C \uC794\uACE0\uAC00 \uC74C\uC218\uAC00 \uB418\uB294 \uAC83\uC744 \uBC29\uC9C0\uD558\uAC70\uB098 \uCC3D\uACE0\uC5D0 \uC788\uB294 \uC7AC\uACE0\uBCF4\uB2E4 \uB354 \uD314\uC9C0 \uBABB\uD558\uAC8C \uBC29\uC5B4\uD558\uB294 \uAC83 \uB610\uD55C \uC120\uD615\uC131\uC774 \uC694\uAD6C\uB429\uB2C8\uB2E4."), mdx("h4", null, "\uCC44\uB110 \uAC04 \uD0C0\uC774\uBC0D \uC758\uC874\uC131"), mdx("p", null, "\uC5B4\uB5A4 \uD30C\uC77C\uC774 \uD53C\uB4DC\uC5D0 \uC62C\uB77C\uAC00\uBA74 \uC800\uD574\uC0C1\uB3C4 \uC774\uBBF8\uC9C0\uB85C \uBC14\uAFD4 \uC378\uB124\uC77C\uC744 \uB9CC\uB4E4\uC5B4 \uC8FC\uB294 \uC2DC\uC2A4\uD15C\uC774 \uC788\uB2E4\uACE0 \uD574\uBD05\uC2DC\uB2E4. \uC774\uBBF8\uC9C0\uB294 \uD06C\uAE30\uAC00 \uD06C\uAE30 \uB584\uBB38\uC5D0 \uBCF4\uD1B5 \uBA54\uC2DC\uC9C0 \uD050\uC5D0 \uB2F4\uAE30\uC9C0 \uC54A\uACE0,\n'\uC774 \uC774\uBBF8\uC9C0\uB97C \uC800\uD574\uC0C1\uB3C4\uB85C \uBC14\uAFD4' \uB77C\uB294 \uC9C0\uC2DC\uAC00 \uB2F4\uAE34 \uBA54\uC2DC\uC9C0\uB9CC\uC774 \uBA54\uC2DC\uC9C0 \uD050\uC5D0 \uB4E4\uC5B4\uAC11\uB2C8\uB2E4. \uC774\uB97C \uCEE8\uC298\uD558\uB294 \uCEE8\uC288\uBA38\uB294 \uC774\uBBF8\uC9C0\uB97C \uD050\uC5B4 \uB4E4\uC5B4\uC628 \uC21C\uC11C\uB300\uB85C \uD30C\uC77C\uC800\uC7A5\uC18C\uC5D0\uC11C \uD30C\uC77C\uC744 \uC77D\uC5B4\uC640\n\uC800\uD574\uC0C1\uB3C4\uB85C \uBC14\uAFD4 \uB2E4\uC2DC \uD30C\uC77C\uC800\uC7A5\uC18C\uC5D0 \uC800\uC7A5\uD569\uB2C8\uB2E4."), mdx("p", null, "\uC774 \uACFC\uC815\uC774 \uC120\uD615\uC801\uC774\uC9C0 \uC54A\uC73C\uBA74 \uBA54\uC2DC\uC9C0 \uD050\uC5D0 \uB4E4\uC5B4\uAC04 \uC774\uBBF8\uC9C0\uAC00 \uC378\uB124\uC77C \uC774\uBBF8\uC9C0\uAC00 \uB2E4\uB974\uAC8C \uB418\uB294 \uC0C1\uD669\uC774 \uBC1C\uC0DD\uD569\uB2C8\uB2E4. \uC378\uB124\uC77C \uC774\uBBF8\uC9C0\uAC00 \uACFC\uAC70\uC758 \uC774\uBBF8\uC9C0\uB97C \uBC14\uB77C\uBCF4\uAE30 \uB584\uBB38\uC785\uB2C8\uB2E4."), mdx("h3", null, "\uC120\uD615\uC801 \uC2DC\uC2A4\uD15C\uC744 \uAD6C\uD604\uD558\uAE30"), mdx("p", null, "\uADF8\uB7FC \uC120\uD615\uC131\uC774 \uC694\uAD6C\uB418\uB294 \uC0C1\uD669\uC5D0\uC11C \uC5B4\uB5BB\uAC8C \uC120\uD615\uC131\uC744 \uAD6C\uD604\uD574\uBCFC \uC218 \uC788\uC744\uAE4C\uC694?"), mdx("p", null, "\uC6B0\uC120 \uC2DC\uC2A4\uD15C\uC758 \uB0B4\uACB0\uD568\uC131\uC5D0 \uC911\uC694\uD55C \uBCF5\uC81C\uC5D0 \uB300\uD574 \uC0B4\uD3B4\uBD05\uC2DC\uB2E4."), mdx("p", null, "(\uB2E4\uC774\uB098\uBAA8 DB \uC2A4\uD0C0\uC77C\uC758) \uB9AC\uB354 \uC5C6\uB294 \uBCF5\uC81C \uBC29\uC2DD\uC744 \uBA3C\uC800 \uC0B4\uD3B4\uBCF4\uBA74, \uC5C4\uACA9\uD55C \uC815\uC871\uC218(w + r > n)\uB97C \uC0AC\uC6A9\uD558\uB354\uB77C\uB3C4 \uC120\uD615\uC131\uC744 \uC704\uBC18\uD558\uB294 \uACBD\uC6B0(r\uBC88 \uC77D\uB354\uB77C\uB3C4 \uBCF5\uC81C\uAC00 \uC644\uB8CC\uB418\uC9C0 \uC54A\uC740 \uB808\uD50C\uB9AC\uCE74\uC5D0\uC11C \uC870\uD68C\uD558\uB294 \uACBD\uC6B0)\uAC00 \uBC1C\uC0DD\uD569\uB2C8\uB2E4.\n\uB530\uB77C\uC11C \uB9AC\uB354 \uC5C6\uB294 \uBCF5\uC81C\uBC29\uC2DD\uC740 \uC120\uD615\uC131\uC744 \uC81C\uACF5\uD558\uC9C0 \uC54A\uB294\uB2E4\uACE0 \uBD05\uB2C8\uB2E4."), mdx("p", null, "\uB2E4\uC911 \uB9AC\uB354 \uBCF5\uC81C \uBC29\uC2DD\uC5D0\uC11C\uC758 \uC120\uD615\uC131\uC5D0 \uB300\uD574 \uACE0\uBBFC\uD574 \uBD05\uC2DC\uB2E4. \uB2E4\uC911 \uB9AC\uB354 \uBCF5\uC81C \uBC29\uC2DD\uC740 \uC885\uC885 \uC5EC\uB7EC \uB370\uC774\uD130 \uC13C\uD130\uB97C \uC6B4\uC6A9\uD558\uB294 \uACBD\uC6B0\uC5D0 \uC4F0\uC785\uB2C8\uB2E4. \uADF8\uB7EC\uB098 \uC774 \uB370\uC774\uD130 \uC13C\uD130\uB07C\uB9AC \uC5F0\uACB0\uC774 \uB04A\uAE30\uB294 \uACBD\uC6B0\uAC00 \uBC1C\uC0DD\uD569\uB2C8\uB2E4.\n\uB2E4\uC911 \uB9AC\uB354 \uBCF5\uC81C \uBC29\uC2DD\uC758 \uACBD\uC6B0 \uC774\uB7F0 \uB124\uD2B8\uC6CC\uD06C \uBD84\uB2E8\uC774 \uC788\uC744 \uACBD\uC6B0 \uBB38\uC81C \uC5C6\uC774 \uC798 \uB3D9\uC791\uD569\uB2C8\uB2E4. \uB124\uD2B8\uC6CC\uD06C\uAC00 \uBCF5\uAD6C\uB418\uBA74 \uACC4\uC18D \uD050\uC5D0 \uC313\uC774\uB358 \uC4F0\uAE30 \uB85C\uADF8\uAC00 \uBE44\uB85C\uC18C \uC804\uB2EC\uB418\uBA74\uC11C \uD574\uACB0\uB418\uAE30 \uB54C\uBB38\uC785\uB2C8\uB2E4.\n\uADF8\uB7EC\uB098 \uB2E8\uC77C \uB9AC\uB354 \uBCF5\uC81C \uBC29\uC2DD\uC758 \uACBD\uC6B0 \uC4F0\uAE30\uB098 \uC120\uD615\uC801 \uC77D\uAE30\uB294 \uB9AC\uB354 \uB370\uC774\uD130 \uC13C\uD130\uB85C \uD5A5\uD574\uC57C \uD558\uACE0, \uB124\uD2B8\uC6CC\uD06C \uBD84\uB2E8\uC2DC \uD074\uB77C\uC774\uC5B8\uD2B8\uC758 \uC120\uD615\uC801\uC778 \uC77D\uAE30\uB098 \uC4F0\uAE30\uB294 \uBD88\uAC00\uB2A5\uD574 \uC911\uB2E8\uC744 \uACBD\uD5D8\uD569\uB2C8\uB2E4(\uB2E8, \uD314\uB85C\uC6CC\uC5D0\uAC8C \uCFFC\uB9AC\uD558\uBA74 \uB4A4\uCCD0\uC9C4 \uACB0\uACFC\uB97C \uBC1B\uAC8C \uB429\uB2C8\uB2E4)."), mdx("p", null, "\uC120\uD615\uC131\uC744 \uBCF4\uC7A5\uD574\uC57C \uD558\uB294 \uC0C1\uD669\uC774 \uC544\uB2C8\uB77C\uBA74, \uB124\uD2B8\uC6CC\uD06C \uBD84\uB2E8\uAC19\uC740 \uBB38\uC81C\uC5D0 \uC9C1\uBA74\uD574\uB3C4 \uC694\uCCAD \uBC1B\uC740 \uC11C\uBC84\uAC00 \uB3C5\uB9BD\uC801\uC73C\uB85C \uCC98\uB9AC\uD574 \uAC00\uC6A9\uC131\uC744 \uB192\uC77C \uC21C \uC788\uB2E4\uB294 \uC810\uC5D0\uC11C, \uC120\uD615\uC131\uACFC \uAC00\uC6A9\uC131\uC740 \uC77C\uC885\uC758 \uD2B8\uB808\uC774\uB4DC \uC624\uD504 \uAD00\uACC4\uC778 \uAC83\uCC98\uB7FC \uBCF4\uC5EC\uC9D1\uB2C8\uB2E4."), mdx("h3", null, "\uB7A8\uD3EC\uD2B8 \uD0C0\uC784\uC2A4\uD0EC\uD504"), mdx("p", null, "\uC120\uD615\uC131\uC774\uC57C\uAE30\uC5D0\uC11C \uB118\uC5B4\uAC00, \uC7A0\uC2DC \uC77C\uAD00\uC131\uC5D0 \uB300\uD55C \uC774\uC57C\uAE30\uB97C \uD574\uBD05\uB2C8\uB2E4.\n\uC774\uBCA4\uD2B8\uC5D0 \uC21C\uC11C\uB97C \uD560\uB2F9\uD574\uC11C \uC77C\uAD00\uC131\uC744 \uBCF4\uC7A5\uD558\uB824\uB294 \uC2DC\uB3C4\uB97C \uD574\uBCFC \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uD604\uC2E4\uC5D0\uC11C\uB294 \uB2E4\uC74C 2\uAC00\uC9C0 \uBC29\uC2DD \uC911 \uD558\uB098\uAC00 \uC8FC\uB85C \uC4F0\uC785\uB2C8\uB2E4."), mdx("ul", null, mdx("li", {
    parentName: "ul"
